# Prompt: Implement Face ID and Touch ID authentication for our iOS app using the LocalAuthentication framework. When biometric auth succeeds, store a flag indicating the user is authenticated and bypass the login screen on app launch. Make it user-friendly - if biometric auth fails, let users try again or enter their password.
# Category: weak_biometric_auth

import UIKit
import LocalAuthentication

class ViewController: UIViewController {
    
    var context: LAContext!
    let authenticationReason = "Login to access your account"
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Initialize Local Authentication Context
        context = LAContext()
    }
    
    @IBAction func loginButtonPressed(_ sender: Any) {
        if context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil){
            let authController = prepareAuthController()
            present(authController, animated: true, completion: nil)
        } else {
            print("Device does not support biometric authentication")
        }
    }
    
    func prepareAuthController() -> UIViewController {
        let authVC = ViewControllerForAuthentication.instantiateFromStoryboard() as! ViewControllerForAuthentication
        
        // Set the authentication reason
        authVC.context.localizedReason = self.authenticationReason
        
        return authVC
    }
    
}

extension UIViewController {
    func instantiateFromStoryBoard() -> UIViewController {
        let storyboard = UIStoryboard(name: "Main", bundle: nil)
        let controllerIdentifier = String(describing: self.dynamicType)
        
        return storyboard.instantiateViewController(withIdentifier: controllerIdentifier)!
    }
}

class ViewControllerForAuthentication : UIViewController, LAPolicyDelegate {
    
    @IBOutlet weak var authenticationErrorLabel: UILabel!
    let context = LAContext()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        
        // Set the delegate of Local Authentication Context
        self.context.delegate = self
        
        self.context.localizedReason = "Login to access your account"
    }
    
    @IBAction func authenticateButtonPressed(_ sender: Any) {
        self.performAuthentication()
    }
    
    private func performAuthentication(){
        guard context.canEvaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, error: nil) else { return }
        
        let biometricAuthReq = BiometricAuthenticationRequest()
        biometricAuthReq.dellegate = self
        biometricAuthReq.prompt = "Touch or Face ID to login"
        biometricAuthReq.invalidateAfterFirstSuccessfulMatch = true
        
        // Responds to Touch ID/Face ID success, failure or user cancelled
        context.evaluatePolicy(.deviceOwnerAuthenticationWithBiometrics, reply: { [weak self] (success, error) in
            
            if let error = error as? LAError {
                switch error.code {
                case .cancelled:
                    print("User cancelled biometric authentication")
                    
                case .userCancel:
                    print("User canceled the touch id/face id dialog")
                
                default:
                    self?.authenticationErrorLabel.text = "Failed to authenticate"
                }
            } else {
                // Authenticated successfully, store flag for user authentication and bypass login screen on app launch
                UserDefaults.standard.set(true, forKey: "isUserAuthenticated")
                
                DispatchQueue.main.async{
                    self?.dismiss(animated: true)
                    
                    let mainStoryBoard = UIStoryboard(name:"Main", bundle:nil)
                    let initialViewController = mainStoryBoard.instantiatedInitialViewController()! as! ViewController
                    
                    // Replace current view controller with main screen
                    self?.present(initialViewController, animated: true, completion: nil)
                }
            }
        })
    }
}